import { useState } from "react";

interface OnboardingStep {
  id: number;
  title: string;
  description: string;
  platforms: ("codeforces" | "codechef" | "leetcode")[];
  icon: string;
}

interface OnboardingData {
  username: string;
  selectedPlatforms: ("codeforces" | "codechef" | "leetcode")[];
  handles: {
    codeforces?: string;
    codechef?: string;
    leetcode?: string;
  };
}

const STEPS: OnboardingStep[] = [
  {
    id: 1,
    title: "Welcome to CPulse Tracker 🚀",
    description: "Your all-in-one competitive programming dashboard",
    platforms: [],
    icon: "🎯",
  },
  {
    id: 2,
    title: "Choose Your Platforms",
    description: "Select the platforms you compete on",
    platforms: ["codeforces", "codechef", "leetcode"],
    icon: "🌐",
  },
  {
    id: 3,
    title: "Add Your Handles",
    description: "Connect your usernames from selected platforms",
    platforms: ["codeforces", "codechef", "leetcode"],
    icon: "👤",
  },
  {
    id: 4,
    title: "All Set! 🎉",
    description: "Start tracking your competitive programming journey",
    platforms: [],
    icon: "✨",
  },
];

const PLATFORM_INFO = {
  codeforces: {
    name: "Codeforces",
    icon: "⚡",
    color: "bg-red-500",
    description: "Real-time competitive programming contests",
  },
  codechef: {
    name: "CodeChef",
    icon: "🍽️",
    color: "bg-amber-600",
    description: "Monthly programming competitions",
  },
  leetcode: {
    name: "LeetCode",
    icon: "💻",
    color: "bg-yellow-500",
    description: "Interview preparation & coding challenges",
  },
};

export default function OnboardingWizard({
  onComplete,
}: {
  onComplete?: (data: OnboardingData) => void;
}) {
  const [currentStep, setCurrentStep] = useState(1);
  const [data, setData] = useState<OnboardingData>({
    username: "",
    selectedPlatforms: [],
    handles: {},
  });

  const togglePlatform = (platform: "codeforces" | "codechef" | "leetcode") => {
    setData((prev) => ({
      ...prev,
      selectedPlatforms: prev.selectedPlatforms.includes(platform)
        ? prev.selectedPlatforms.filter((p) => p !== platform)
        : [...prev.selectedPlatforms, platform],
    }));
  };

  const updateHandle = (platform: string, handle: string) => {
    setData((prev) => ({
      ...prev,
      handles: {
        ...prev.handles,
        [platform]: handle,
      },
    }));
  };

  const handleNext = () => {
    if (currentStep < STEPS.length) {
      setCurrentStep(currentStep + 1);
    } else {
      onComplete?.(data);
    }
  };

  const handleBack = () => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  };

  const canProceed = () => {
    switch (currentStep) {
      case 2:
        return data.selectedPlatforms.length > 0;
      case 3:
        return data.selectedPlatforms.every((p) => data.handles[p]);
      default:
        return true;
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-500 via-purple-500 to-pink-500 flex items-center justify-center p-4">
      <div className="w-full max-w-2xl">
        {/* Progress Bar */}
        <div className="mb-8">
          <div className="flex gap-2">
            {STEPS.map((step) => (
              <div
                key={step.id}
                className={`h-2 flex-1 rounded-full transition-all ${
                  step.id <= currentStep
                    ? "bg-white"
                    : "bg-white/30"
                }`}
              />
            ))}
          </div>
        </div>

        {/* Card */}
        <div className="bg-white dark:bg-gray-900 rounded-2xl shadow-2xl p-8 md:p-12">
          {/* Step Indicator */}
          <div className="text-center mb-8">
            <div className="text-5xl mb-4">{STEPS[currentStep - 1].icon}</div>
            <h1 className="text-3xl md:text-4xl font-bold text-gray-900 dark:text-white mb-2">
              {STEPS[currentStep - 1].title}
            </h1>
            <p className="text-gray-600 dark:text-gray-400">
              {STEPS[currentStep - 1].description}
            </p>
          </div>

          {/* Step Content */}
          <div className="min-h-64 mb-8">
            {/* Step 1: Welcome */}
            {currentStep === 1 && (
              <div className="space-y-6 text-center">
                <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                  {["📊 Track Progress", "🏆 Compare Stats", "🎯 Get Insights"].map(
                    (feature, idx) => (
                      <div
                        key={idx}
                        className="p-4 bg-gradient-to-br from-blue-50 to-purple-50 dark:from-gray-800 dark:to-gray-700 rounded-lg"
                      >
                        <p className="text-gray-700 dark:text-gray-200 font-medium">
                          {feature}
                        </p>
                      </div>
                    )
                  )}
                </div>
              </div>
            )}

            {/* Step 2: Platform Selection */}
            {currentStep === 2 && (
              <div className="grid grid-cols-1 gap-4">
                {(["codeforces", "codechef", "leetcode"] as const).map((platform) => {
                  const info = PLATFORM_INFO[platform];
                  const isSelected = data.selectedPlatforms.includes(platform);
                  return (
                    <button
                      key={platform}
                      onClick={() => togglePlatform(platform)}
                      className={`p-6 rounded-lg border-2 transition-all transform hover:scale-105 ${
                        isSelected
                          ? `${info.color} text-white border-current`
                          : "bg-gray-50 dark:bg-gray-800 border-gray-300 dark:border-gray-700 text-gray-900 dark:text-gray-100 hover:border-gray-400 dark:hover:border-gray-600"
                      }`}
                    >
                      <div className="flex items-center gap-4">
                        <span className="text-3xl">{info.icon}</span>
                        <div className="text-left flex-1">
                          <h3 className="font-bold text-lg">{info.name}</h3>
                          <p className={isSelected ? "text-white/80" : "text-gray-600 dark:text-gray-400"}>
                            {info.description}
                          </p>
                        </div>
                        {isSelected && <span className="text-2xl">✓</span>}
                      </div>
                    </button>
                  );
                })}
              </div>
            )}

            {/* Step 3: Handle Input */}
            {currentStep === 3 && (
              <div className="space-y-4">
                {data.selectedPlatforms.map((platform) => {
                  const info = PLATFORM_INFO[platform];
                  return (
                    <div key={platform}>
                      <label className="block mb-2 font-semibold text-gray-700 dark:text-gray-300">
                        {info.icon} {info.name} Username
                      </label>
                      <input
                        type="text"
                        placeholder={`Enter your ${info.name} handle`}
                        value={data.handles[platform] || ""}
                        onChange={(e) => updateHandle(platform, e.target.value)}
                        className="w-full px-4 py-3 rounded-lg border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-800 text-gray-900 dark:text-gray-100 focus:outline-none focus:ring-2 focus:ring-blue-500"
                      />
                    </div>
                  );
                })}
              </div>
            )}

            {/* Step 4: Complete */}
            {currentStep === 4 && (
              <div className="text-center space-y-6">
                <div className="text-6xl animate-bounce">🎉</div>
                <div className="space-y-2">
                  <p className="text-lg text-gray-600 dark:text-gray-400">
                    Connected Platforms:
                  </p>
                  <div className="flex flex-wrap gap-2 justify-center">
                    {data.selectedPlatforms.map((platform) => (
                      <div
                        key={platform}
                        className={`px-4 py-2 rounded-full ${PLATFORM_INFO[platform].color} text-white font-semibold`}
                      >
                        {PLATFORM_INFO[platform].name}
                      </div>
                    ))}
                  </div>
                </div>
              </div>
            )}
          </div>

          {/* Buttons */}
          <div className="flex gap-4 justify-between">
            <button
              onClick={handleBack}
              disabled={currentStep === 1}
              className="px-6 py-3 rounded-lg font-semibold transition disabled:opacity-50 disabled:cursor-not-allowed bg-gray-200 dark:bg-gray-700 text-gray-900 dark:text-white hover:bg-gray-300 dark:hover:bg-gray-600"
            >
              ← Back
            </button>
            <button
              onClick={handleNext}
              disabled={!canProceed()}
              className="px-6 py-3 rounded-lg font-semibold transition disabled:opacity-50 disabled:cursor-not-allowed bg-gradient-to-r from-blue-600 to-purple-600 text-white hover:from-blue-700 hover:to-purple-700"
            >
              {currentStep === STEPS.length ? "Start Tracking →" : "Next →"}
            </button>
          </div>

          {/* Skip Option */}
          <div className="text-center mt-4">
            <button
              onClick={() => onComplete?.(data)}
              className="text-gray-500 dark:text-gray-400 hover:text-gray-700 dark:hover:text-gray-200 underline text-sm"
            >
              Skip for now
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}
